mapper.insert:
insert into jst_cert_template (
    template_name, owner_type, owner_id, bg_image, layout_json, audit_status,
    status, create_by, create_time, update_by, update_time, remark, del_flag
) values (
    #{templateName}, #{ownerType}, #{ownerId}, #{bgImage}, #{layoutJson}, #{auditStatus},
    #{status}, #{createBy}, #{createTime}, #{updateBy}, #{updateTime}, #{remark}, #{delFlag}
)

mapper.select:
select cr.cert_id as certId, cr.cert_no as certNo, cr.contest_id as contestId, c.contest_name as contestName, cr.score_id as scoreId, cr.enroll_id as enrollId, er.enroll_no as enrollNo, cr.user_id as userId, cr.participant_id as participantId, p.name as participantName, p.guardian_mobile as guardianMobileMasked, cr.template_id as templateId, t.template_name as templateName, cr.cert_file_url as certFileUrl, cr.issue_status as issueStatus, cr.issue_time as issueTime, cr.verify_code as verifyCode, s.award_level as awardLevel from jst_cert_record cr left join jst_contest c on c.contest_id = cr.contest_id and c.del_flag = '0' left join jst_score_record s on s.score_id = cr.score_id and s.del_flag = '0' left join jst_enroll_record er on er.enroll_id = cr.enroll_id and er.del_flag = '0' left join jst_participant p on p.participant_id = cr.participant_id and p.del_flag = '0' left join jst_cert_template t on t.template_id = cr.template_id and t.del_flag = '0'
cr.del_flag = '0'
and cr.contest_id = #{contestId}
and cr.cert_no = #{certNo}
and p.name like concat('%', #{participantName}, '%')
and cr.issue_status = #{issueStatus}
and cr.issue_status = 'issued'
and cr.issue_status = #{displayStatus}
${params.dataScope}
order by cr.update_time desc, cr.cert_id desc

mapper.insert:
insert into jst_cert_record (
    cert_no, contest_id, score_id, enroll_id, user_id, participant_id,
    template_id, cert_file_url, issue_status, verify_code, create_by,
    create_time, update_by, update_time, remark, del_flag
) values (
    #{certNo}, #{contestId}, #{scoreId}, #{enrollId}, #{userId}, #{participantId},
    #{templateId}, #{certFileUrl}, #{issueStatus}, #{verifyCode}, #{createBy},
    #{createTime}, #{updateBy}, #{updateTime}, #{remark}, #{delFlag}
)

mapper.update:
update jst_cert_record
set issue_status = #{targetIssueStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}
where cert_id = #{certId}
  and issue_status = #{expectedIssueStatus}
  and del_flag = '0'
